// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData, onSuccess, onError }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [showCODOption, setShowCODOption] = useState(false);

  useEffect(() => {
    if (amount && amount > 0) {
      handleSubmit(amount);
    }
  }, [amount]);

  const handleSubmit = async (submitAmount) => {
    setIsLoading(true);
    setError("");
    setShowCODOption(false);

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required. Please login.");
        setIsLoading(false);
        return;
      }

      // Convert amount to paise
      const amountInPaise = Math.round(submitAmount * 100);

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: amountInPaise,
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      const data = await response.json();
      console.log("Payment response:", data);
      
      if (data.success) {
        // Payment successful - redirect to gateway
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = data.data.APIURL;
        form.target = '_blank';
        
        Object.entries(data.data).forEach(([key, value]) => {
          if (key !== 'APIURL' && value) {
            const input = document.createElement('input');
            input.type = 'hidden';
            input.name = key.toUpperCase();
            input.value = value;
            form.appendChild(input);
          }
        });
        
        document.body.appendChild(form);
        form.submit();
        document.body.removeChild(form);
        
        if (onSuccess) {
          onSuccess("Redirecting to payment gateway...");
        }
      } else {
        // Check if it's the amount limit error
        if (data.message?.includes("50000") || data.code === 400) {
          setError(`Payment gateway accepts only amounts up to ₹50,000. Your order amount is ₹${amount.toLocaleString('en-IN')}.`);
          setShowCODOption(true);
        } else {
          setError(data.message || "Payment failed. Please try again.");
        }
        if (onError) onError(data.message);
      }
    } catch (err) {
      console.error('Payment error:', err);
      setError("Network error. Please check your connection.");
      if (onError) onError("Network error");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {/* Loading State */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <div>
            <p style={{margin: '0 0 5px 0', fontWeight: '500'}}>Connecting to payment gateway...</p>
            <p style={{margin: '0', fontSize: '12px', color: '#666'}}>Please wait</p>
          </div>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          <div style={{marginBottom: showCODOption ? '15px' : '0'}}>
            <strong style={{color: '#dc2626', display: 'block', marginBottom: '5px'}}>
              ⚠️ Payment Gateway Limitation
            </strong>
            <p style={{margin: '0', color: '#991b1b'}}>{error}</p>
          </div>
          
          {showCODOption && (
            <div style={{
              marginTop: '15px',
              padding: '15px',
              background: '#fff3cd',
              border: '1px solid #ffeeba',
              borderRadius: '8px'
            }}>
              <p style={{margin: '0 0 10px 0', color: '#856404'}}>
                <strong>💡 Suggestion:</strong> Use Cash on Delivery for this order.
              </p>
              <button 
                onClick={() => {
                  setError("");
                  setShowCODOption(false);
                  if (onError) onError("Please use COD");
                }}
                style={{
                  padding: '10px 20px',
                  background: '#16a34a',
                  color: 'white',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  fontSize: '14px',
                  fontWeight: '500',
                  width: '100%'
                }}
              >
                Use Cash on Delivery
              </button>
            </div>
          )}
        </div>
      )}

      {/* Initial Message */}
      {!isLoading && !error && (
        <div className="info-message">
          <p>⚡ Initializing secure payment for ₹{amount.toLocaleString('en-IN')}...</p>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
